solutions.python:
class TrieNode:
    def __init__(self):
        self.endOfWord = False
        self.children = [None]*26

    def insert(self, word):
        node = self
        for char in word:
            index = ord(char) - ord('a')
            if node.children[index] is None:
                node.children[index] = TrieNode()
            node = node.children[index]
        node.endOfWord = True

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        self.root.insert(word)

def insert(word):
    trie = Trie()
    trie.insert(word)

# Test the code
insert('apple')

