#include <iostream>
#include <string>

using namespace std;

class TrieNode {
    public:
        bool endOfWord;
        TrieNode* children[26];

        TrieNode() : endOfWord(false) {}
    };

void insert(string& word, TrieNode* root) {
    node = root;
    for (char c : word)
    {
        int index = c - 'a';
        if (node->children[index] == nullptr)
        {
            node->children[index] = new TrieNode();
        }
        node = node->children[index];
    }
    node->endOfWord = true;
}

int main()
{
    insert("apple");

    return 0;
}
